/*
 * PHASE-21 FROZEN FLOOR CONTENT INJECTION INTERFACE
 *
 * The run loop consumes floor content; it never selects content. Fallback packs and
 * the Director both implement FloorContentProvider#getFloor(depth, seed), returning
 * already-authored floor params plus content definitions. The engine validates,
 * generates geometry, places content, and assembles runtime entities through
 * deterministic code only.
 */

import {
  config as defaultConfig,
  type GameConfig
} from "../../config/index.js";
import {
  EnemyDefinitionSchema,
  ItemDefinitionSchema,
  NpcDefinitionSchema,
  QuestDefinitionSchema,
  TrapDefinitionSchema,
  type DepthBand,
  type EnemyDefinition,
  type ItemDefinition,
  type NpcDefinition,
  type QuestDefinition,
  type TrapDefinition
} from "../../schemas/entities/index.js";
import {
  LAYOUT_FLAVORS,
  generateFloor,
  type FloorParams,
  type GeneratedFloor,
  type LayoutFlavor,
  type RoomCountRange
} from "../floorgen/index.js";
import {
  allocateCells,
  collectLegalPlacementCells,
  type PlacementDeviation,
  type PlacementGrid,
  type PlacementHint,
  type PlacementRequest
} from "../floorgen/place.js";
import { costOf, rosterAffordable, rosterCost } from "../enemies/index.js";
import { assembleEnemy } from "../enemies/index.js";
import { createFloorGeometrySlot, type TileGrid } from "../map/index.js";
import { createRng, type Rng } from "../rng/index.js";
import {
  allocateEntityId,
  depthBandForDepth,
  type EntityIdCounters,
  type EntityMap,
  type EntityInstance,
  type GameState,
  type GroundItemEntityInstance,
  type NpcEntityInstance,
  type Position,
  type QuestRuntime,
  type SerializableRecord,
  type TrapEntityInstance
} from "../state/index.js";
import {
  step as turnStep,
  start as turnStart,
  type PlayerAction,
  type TurnEvent,
  type TurnHooks
} from "../turn/index.js";
import { takeOneThingAtHoard, type TakeHoardAction } from "./endings.js";
import { appendRunLog, runEvent, type RunEvent } from "./events.js";

export type HoardFeatureParams = {
  readonly id?: string;
  readonly name?: string;
  readonly hint?: PlacementHint;
};

export type RunFloorParams = FloorParams & {
  readonly hoard?: HoardFeatureParams;
};

export type FloorContent = {
  readonly params: RunFloorParams;
  readonly roster: readonly EnemyDefinition[];
  readonly items: readonly ItemDefinition[];
  readonly traps: readonly TrapDefinition[];
  readonly npcs: readonly NpcDefinition[];
  readonly quest?: QuestDefinition;
};

export interface FloorContentProvider {
  readonly getFloor: (depth: number, seed: string) => FloorContent;
}

export type RunAction = PlayerAction | TakeHoardAction;

export type RunStepOptions = {
  readonly hooks?: TurnHooks;
  readonly config?: GameConfig;
};

export type RunStartOptions = {
  readonly config?: GameConfig;
};

export type RunLoopErrorCode =
  | "provider_threw"
  | "provider_result_malformed"
  | "roster_unaffordable"
  | "floor_generation_failed"
  | "placement_failed"
  | "depth_out_of_range";

export type RunLoopError = {
  readonly kind: "run-loop-error";
  readonly code: RunLoopErrorCode;
  readonly depth: number;
  readonly message: string;
};

export type RunLoopSuccess = {
  readonly ok: true;
  readonly state: GameState;
  readonly events: readonly RunEvent[];
};

export type RunLoopFailure = {
  readonly ok: false;
  readonly state: GameState;
  readonly events: readonly RunEvent[];
  readonly error: RunLoopError;
};

export type RunLoopResult = RunLoopSuccess | RunLoopFailure;

type FloorRuntime = {
  readonly depth: number;
  readonly enteredTurn: number;
  readonly seed: string;
  readonly entrance: Position;
  readonly stairsDown: Position;
  readonly roster: readonly EnemyDefinition[];
  readonly initialSpawnBudgetSpent: number;
  readonly reinforcementSpawnBudgetSpent: number;
  readonly hoard: HoardRuntime | null;
};

type HoardRuntime = {
  readonly id: string;
  readonly name: string;
  readonly position: Position;
};

type FloorRuntimeOpaque = TileGrid & {
  readonly knowledge?: {
    readonly decorativeFeatures?: readonly SerializableRecord[];
    readonly run?: FloorRuntime;
  };
};

type ContentRequest =
  | {
      readonly request: PlacementRequest;
      readonly kind: "enemy";
      readonly definition: EnemyDefinition;
    }
  | {
      readonly request: PlacementRequest;
      readonly kind: "item";
      readonly definition: ItemDefinition;
    }
  | {
      readonly request: PlacementRequest;
      readonly kind: "trap";
      readonly definition: TrapDefinition;
    }
  | {
      readonly request: PlacementRequest;
      readonly kind: "npc";
      readonly definition: NpcDefinition;
    }
  | {
      readonly request: PlacementRequest;
      readonly kind: "hoard";
      readonly params: Required<Pick<HoardFeatureParams, "id" | "name">> &
        Pick<HoardFeatureParams, "hint">;
    };

export const startRun = (
  seed: string,
  provider: FloorContentProvider,
  options: RunStartOptions = {}
): RunLoopResult => {
  const gameConfig = options.config ?? defaultConfig;
  const state = turnStart(seed, { config: gameConfig });

  return enterFloor(state, provider, state.run.depth, gameConfig);
};

export const stepRun = (
  state: GameState,
  action: RunAction,
  provider: FloorContentProvider,
  options: RunStepOptions = {}
): RunLoopResult => {
  const gameConfig = options.config ?? defaultConfig;

  if (action.kind === "take_hoard") {
    const resolved = takeOneThingAtHoard(state);
    if ("illegal" in resolved) {
      return success(state, [
        runEvent(state.run.turn, "run_action_illegal", {
          actionKind: action.kind,
          reason: resolved.reason
        })
      ]);
    }

    const events = [
      runEvent(state.run.turn, "run_action_resolved", {
        actionKind: action.kind
      }),
      ...resolved.events
    ];

    return success(appendRunLog(resolved.state, events), events);
  }

  if (
    action.kind === "descend" &&
    state.run.depth >= gameConfig.runStructure.depthFloors
  ) {
    return success(state, [
      runEvent(state.run.turn, "run_action_illegal", {
        actionKind: action.kind,
        reason: "the final floor ends at the Hoard, not the stairs"
      })
    ]);
  }

  const stepped = turnStep(state, action, { hooks: options.hooks });
  if (
    actionWasIllegal(stepped.events) ||
    stepped.state.run.terminalStatus !== "ACTIVE"
  ) {
    return success(stepped.state, stepped.events);
  }

  if (action.kind === "descend") {
    const nextDepth = state.run.depth + 1;
    const entered = enterFloor(stepped.state, provider, nextDepth, gameConfig);
    if (!entered.ok) {
      return entered;
    }

    return success(entered.state, [...stepped.events, ...entered.events]);
  }

  const softCap = applySoftCap(stepped.state, gameConfig);
  return success(softCap.state, [...stepped.events, ...softCap.events]);

import type {
  EntityId,
  EntityInstance,
  GameState,
  InventorySlot,
  Position,
  SerializableRecord,
} from "../state/index.js";
import {
  chebyshevDistance,
  getTile,
  inBounds,
  isWalkableTile,
  Terrain,
  type TileGrid,
} from "../map/index.js";

export const MOVE_DIRECTIONS = [
  { direction: "northwest", offset: { x: -1, y: -1 } },
  { direction: "north", offset: { x: 0, y: -1 } },
  { direction: "northeast", offset: { x: 1, y: -1 } },
  { direction: "west", offset: { x: -1, y: 0 } },
  { direction: "east", offset: { x: 1, y: 0 } },
  { direction: "southwest", offset: { x: -1, y: 1 } },
  { direction: "south", offset: { x: 0, y: 1 } },
  { direction: "southeast", offset: { x: 1, y: 1 } },
] as const;

export type MoveDirection = (typeof MOVE_DIRECTIONS)[number]["direction"];

export type ActionTarget =
  | {
      readonly kind: "self";
    }
  | {
      readonly kind: "entity";
      readonly entityId: EntityId;
    }
  | {
      readonly kind: "cell";
      readonly cell: Position;
    };

export type MoveAction = {
  readonly kind: "move";
  readonly direction: MoveDirection;
};

export type AttackAction = {
  readonly kind: "attack";
  readonly targetId: EntityId;
};

export type UseItemAction = {
  readonly kind: "use_item";
  readonly itemId: string;
  readonly target?: ActionTarget;
  readonly direction?: MoveDirection;
};

export type PickupAction = {
  readonly kind: "pickup";
};

export type TalkAction = {
  readonly kind: "talk";
  readonly npcId: EntityId;
};

export type WaitAction = {
  readonly kind: "wait";
};

export type DescendAction = {
  readonly kind: "descend";
};

export type InspectAction = {
  readonly kind: "inspect";
  readonly cell: Position;
};

export type AbortAction = {
  readonly kind: "abort";
};

export type PlayerAction =
  | MoveAction
  | AttackAction
  | UseItemAction
  | PickupAction
  | TalkAction
  | WaitAction
  | DescendAction
  | InspectAction
  | AbortAction;

export type LegalActionResult = {
  readonly status: "legal";
};

export type IllegalActionResult = {
  readonly status: "illegal";
  readonly reason: string;
};

export type ActionLegality = LegalActionResult | IllegalActionResult;

export const LEGAL_ACTION = { status: "legal" } as const satisfies ActionLegality;

export const isActionLegal = (
  result: ActionLegality,
): result is LegalActionResult => result.status === "legal";

export const checkActionLegality = (
  state: GameState,
  action: PlayerAction,
): ActionLegality => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return illegal(`run is terminal (${state.run.terminalStatus})`);
  }

  switch (action.kind) {
    case "move":
      return checkMoveAction(state, action);
    case "attack":
      return checkAttackAction(state, action);
    case "use_item":
      return checkUseItemAction(state, action);
    case "pickup":
      return checkPickupAction(state);
    case "talk":
      return checkTalkAction(state, action);
    case "wait":
      return LEGAL_ACTION;
    case "descend":
      return checkDescendAction(state);
    case "inspect":
      return checkInspectAction(state, action);
    case "abort":
      return LEGAL_ACTION;
  }
};

export const getAvailableActions = (state: GameState): readonly PlayerAction[] => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return [];
  }

  const actions: PlayerAction[] = [];

  for (const { direction } of MOVE_DIRECTIONS) {
    const action = { kind: "move", direction } as const;
    pushIfLegal(actions, state, action);
  }

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "enemy") {
      pushIfLegal(actions, state, {
        kind: "attack",
        targetId: entity.id,
      });
    }
  }

  for (const item of carriedItems(state.player.inventory)) {
    pushIfLegal(actions, state, {
      kind: "use_item",
      itemId: item.itemInstanceId,
    });
  }

  pushIfLegal(actions, state, { kind: "pickup" });

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "npc") {
      pushIfLegal(actions, state, {
        kind: "talk",
        npcId: entity.id,
      });
    }
  }

  pushIfLegal(actions, state, { kind: "wait" });
  pushIfLegal(actions, state, { kind: "descend" });
  actions.push(...availableInspectActions(state));
  pushIfLegal(actions, state, { kind: "abort" });

  return actions;
};

export const destinationForMove = (
  origin: Position,
  direction: MoveDirection,
): Position => {
  const offset = offsetForDirection(direction);

  return {
    x: origin.x + offset.x,
    y: origin.y + offset.y,
  };
};

export const gridFromState = (state: GameState): TileGrid | null => {
  const opaque = state.floor.geometry.opaque;

  if (!isTileGridRecord(opaque)) {
    return null;
  }

  return opaque as unknown as TileGrid;
};

const checkMoveAction = (
  state: GameState,
  action: MoveAction,
): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  const destination = destinationForMove(state.player.position, action.direction);

  if (!inBounds(grid, destination)) {
    return illegal(
      `move ${action.direction} leaves the map at (${destination.x}, ${destination.y})`,
    );
  }

  const tile = getTile(grid, destination);

  if (!isWalkableTile(tile)) {
    return illegal(`terrain ${tile.terrain} blocks movement`);
  }

  return LEGAL_ACTION;
};

const checkAttackAction = (
  state: GameState,
  action: AttackAction,
): ActionLegality => {
  const target = state.entities[action.targetId];

  if (target === undefined) {
    return illegal(`attack target ${action.targetId} does not exist`);
  }

  if (target.kind !== "enemy") {
    return illegal(`attack target ${action.targetId} is not an enemy`);
  }

  if (!isAdjacentToPlayer(state, target.position)) {
    return illegal(`attack target ${action.targetId} is not adjacent`);
  }

  return LEGAL_ACTION;
};

/*
 * PHASE-07B FROZEN TURN EXTENSION INTERFACE
 *
 * A turn always resolves in this order:
 * 1. the player action resolves through built-in handling or the action-resolver
 *    registry;
 * 2. every other actor runs exactly once in stable actor-id order;
 * 3. end-of-turn tick hooks run in this fixed order:
 *    damageOverTime -> durations -> hunger -> regen.
 *
 * Frozen extension surface:
 * - registerActionResolver handles move/attack/use_item/pickup/talk/inspect.
 * - registerTickHook handles damageOverTime/durations/hunger/regen.
 * - TurnHooks.actorTurn handles non-player actors in stable actor-id order.
 * - TurnHooks.ticks handles per-step tick overrides.
 *
 * Do not rename action kinds or TickHookName values, reorder TICK_HOOK_ORDER, or
 * let resolvers/hooks call ambient nondeterminism or LLMs. Resolvers and hooks
 * must return deterministic state/events.
 */

import { bounds, config, type GameConfig } from "../../config/index.js";
import { createClock } from "../clock/index.js";
import {
  ACTIVE_TERMINAL_STATUS,
  createInitialState,
  type EngineLogEvent,
  type EntityId,
  type EntityInstance,
  type GameState,
  type TerminalStatus,
} from "../state/index.js";
import {
  checkActionLegality,
  type PlayerAction,
} from "./actions.js";

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly action_illegal: {
      readonly actionKind: PlayerAction["kind"];
      readonly reason: string;
    };
    readonly action_resolved: {
      readonly actionKind: PlayerAction["kind"];
    };
    readonly actor_turn: {
      readonly actorId: EntityId;
    };
    readonly tick_hook: {
      readonly hook: TickHookName;
    };
    readonly terminal_state: {
      readonly status: Exclude<TerminalStatus, "ACTIVE">;
      readonly reason: string;
    };
  }
}

export { checkActionLegality, getAvailableActions } from "./actions.js";
export type {
  AbortAction,
  ActionLegality,
  ActionTarget,
  AttackAction,
  DescendAction,
  InspectAction,
  MoveAction,
  MoveDirection,
  PickupAction,
  PlayerAction,
  TalkAction,
  UseItemAction,
  WaitAction,
} from "./actions.js";

export type TurnEvent = EngineLogEvent;

export type ActorEntity = Extract<EntityInstance, { readonly kind: "enemy" | "npc" }>;

export type ActionResolverActionKind =
  | "move"
  | "attack"
  | "use_item"
  | "pickup"
  | "talk"
  | "inspect";

export type ActionResolverAction = Extract<
  PlayerAction,
  { readonly kind: ActionResolverActionKind }
>;

export type ActionResolverSuccess = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export type ActionResolverIllegal = {
  readonly illegal: true;
  readonly reason: string;
};

export type ActionResolverResult =
  | ActionResolverSuccess
  | ActionResolverIllegal;

export type ActionResolver<
  Action extends ActionResolverAction = ActionResolverAction,
> = (state: GameState, action: Action) => ActionResolverResult;

export type TickHookName =
  | "damageOverTime"
  | "durations"
  | "hunger"
  | "regen";

export const TICK_HOOK_ORDER = [
  "damageOverTime",
  "durations",
  "hunger",
  "regen",
] as const satisfies readonly TickHookName[];

export type TurnHookResult =
  | GameState
  | {
      readonly state: GameState;
      readonly events?: readonly TurnEvent[];
    };

export type ActorTurnHook = (context: {
  readonly state: GameState;
  readonly actor: ActorEntity;
  readonly action: PlayerAction;
}) => TurnHookResult;

export type TickHook = (context: {
  readonly state: GameState;
  readonly hook: TickHookName;
  readonly action: PlayerAction;
}) => TurnHookResult;

export type TickHooks = {
  readonly [Hook in TickHookName]: TickHook;
};

export type TurnHooks = {
  readonly actorTurn?: ActorTurnHook;
  readonly ticks?: Partial<TickHooks>;
};

export type ResolvedTurnHooks = {
  readonly actorTurn: ActorTurnHook;
  readonly ticks: TickHooks;
};

export type StepOptions = {
  readonly hooks?: TurnHooks;
};

export type StepResult = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export type StartContent = {
  readonly config?: GameConfig;
};

const actionResolvers = new Map<ActionResolverActionKind, ActionResolver>();
const tickHookRegistry = new Map<TickHookName, TickHook>();

export const registerActionResolver = <
  Kind extends ActionResolverActionKind,
>(
  actionType: Kind,
  resolver: ActionResolver<Extract<PlayerAction, { readonly kind: Kind }>>,
): (() => void) => {
  const previous = actionResolvers.get(actionType);
  const registeredResolver = resolver as ActionResolver;
  actionResolvers.set(actionType, registeredResolver);

  return () => {
    if (actionResolvers.get(actionType) !== registeredResolver) {
      return;
    }

    if (previous === undefined) {
      actionResolvers.delete(actionType);
      return;
    }

    actionResolvers.set(actionType, previous);
  };
};

export const registerTickHook = (
  slot: TickHookName,
  hook: TickHook,
): (() => void) => {
  const previous = tickHookRegistry.get(slot);
  tickHookRegistry.set(slot, hook);

  return () => {
    if (tickHookRegistry.get(slot) !== hook) {
      return;
    }

    if (previous === undefined) {
      tickHookRegistry.delete(slot);
      return;
    }

    tickHookRegistry.set(slot, previous);
  };
};

export const start = (seed: string, content: StartContent = {}): GameState =>
  createInitialState(seed, content.config ?? config);

export const step = (
  state: GameState,
  action: PlayerAction,
  options: StepOptions = {},
): StepResult => {
  if (isTerminal(state)) {
    return illegalStep(
      state,
      action,
      `run is terminal (${state.run.terminalStatus})`,
    );
  }

  const legality = checkActionLegality(state, action);
  if (legality.status === "illegal") {
    return illegalStep(state, action, legality.reason);
  }

  const forcedTerminal = forcedTerminalFor(state);
  if (forcedTerminal !== null) {
    return terminalStep(state, forcedTerminal.status, forcedTerminal.reason);
  }

  const hooks = resolveTurnHooks(options.hooks);
  const playerActionResult = applyPlayerAction(state, action);
  if (isActionResolverIllegal(playerActionResult)) {
    return illegalStep(state, action, playerActionResult.reason);
  }

  const events: TurnEvent[] = [
    turnEvent(state.run.turn, "action_resolved", {
      actionKind: action.kind,
    }),
    ...playerActionResult.events,
  ];

  let nextState = playerActionResult.state;

  if (!isTerminal(nextState)) {

  const previous = actionResolvers.get(actionType);
  const registeredResolver = resolver as ActionResolver;
  actionResolvers.set(actionType, registeredResolver);

  return () => {
    if (actionResolvers.get(actionType) !== registeredResolver) {
      return;
    }

    if (previous === undefined) {
      actionResolvers.delete(actionType);
      return;
    }

    actionResolvers.set(actionType, previous);
  };
};

export const registerTickHook = (
  slot: TickHookName,
  hook: TickHook,
): (() => void) => {
  const previous = tickHookRegistry.get(slot);
  tickHookRegistry.set(slot, hook);

  return () => {
    if (tickHookRegistry.get(slot) !== hook) {
      return;
    }

    if (previous === undefined) {
      tickHookRegistry.delete(slot);
      return;
    }

    tickHookRegistry.set(slot, previous);
  };
};

export const start = (seed: string, content: StartContent = {}): GameState =>
  createInitialState(seed, content.config ?? config);

export const step = (
  state: GameState,
  action: PlayerAction,
  options: StepOptions = {},
): StepResult => {
  if (isTerminal(state)) {
    return illegalStep(
      state,
      action,
      `run is terminal (${state.run.terminalStatus})`,
    );
  }

  const legality = checkActionLegality(state, action);
  if (legality.status === "illegal") {
    return illegalStep(state, action, legality.reason);
  }

  const forcedTerminal = forcedTerminalFor(state);
  if (forcedTerminal !== null) {
    return terminalStep(state, forcedTerminal.status, forcedTerminal.reason);
  }

  const hooks = resolveTurnHooks(options.hooks);
  const playerActionResult = applyPlayerAction(state, action);
  if (isActionResolverIllegal(playerActionResult)) {
    return illegalStep(state, action, playerActionResult.reason);
  }

  const events: TurnEvent[] = [
    turnEvent(state.run.turn, "action_resolved", {
      actionKind: action.kind,
    }),
    ...playerActionResult.events,
  ];

  let nextState = playerActionResult.state;

  if (!isTerminal(nextState)) {
    for (const actor of actorsInTurnOrder(nextState)) {
      events.push(
        turnEvent(nextState.run.turn, "actor_turn", {
          actorId: actor.id,
        }),
      );

      const result = normalizeHookResult(
        hooks.actorTurn({
          state: nextState,
          actor,
          action,
        }),
      );
      nextState = result.state;
      events.push(...result.events);

      if (isTerminal(nextState)) {
        break;
      }
    }
  }

  if (!isTerminal(nextState)) {
    for (const hook of TICK_HOOK_ORDER) {
      events.push(
        turnEvent(nextState.run.turn, "tick_hook", {
          hook,
        }),
      );

      const result = normalizeHookResult(
        hooks.ticks[hook]({
          state: nextState,
          hook,
          action,
        }),
      );
      nextState = result.state;
      events.push(...result.events);

      if (isTerminal(nextState)) {
        break;
      }
    }
  }

  if (!isTerminal(nextState)) {
    nextState = advanceTurn(nextState);

    const terminal = forcedTerminalFor(nextState);
    if (terminal !== null) {
      nextState = withTerminalStatus(nextState, terminal.status);
      events.push(
        turnEvent(nextState.run.turn, "terminal_state", {
          status: terminal.status,
          reason: terminal.reason,
        }),
      );
    }
  }

  nextState = appendLog(nextState, events);

  return {
    state: nextState,
    events,
  };
};

export const render = (state: GameState): string =>
  [
    `run=${state.run.runId}`,
    `turn=${state.run.turn}`,
    `depth=${state.run.depth}`,
    `status=${state.run.terminalStatus}`,
    `player=(${state.player.position.x},${state.player.position.y})`,
    `hp=${state.player.hp.current}/${state.player.hp.max}`,
  ].join(" ");

export const isTerminal = (state: GameState): boolean =>
  state.run.terminalStatus !== ACTIVE_TERMINAL_STATUS;

export const createNoopTurnHooks = (): ResolvedTurnHooks => ({
  actorTurn: ({ state }) => state,
  ticks: {
    damageOverTime: ({ state }) => state,
    durations: ({ state }) => state,
    hunger: ({ state }) => state,
    regen: ({ state }) => state,
  },
});

const applyPlayerAction = (
  state: GameState,
  action: PlayerAction,
): ActionResolverResult => {
  if (action.kind === "abort") {
    const status = config.runStructure.terminalStates.abort;
    const terminalState = withTerminalStatus(state, status);

    return {
      state: terminalState,
      events: [
        turnEvent(state.run.turn, "terminal_state", {
          status,
          reason: "player aborted the run",
        }),
      ],
    };
  }

  if (
    action.kind === "descend" &&
    state.run.depth >= config.runStructure.depthFloors
  ) {
    const status = config.runStructure.terminalStates.win;
    const terminalState = withTerminalStatus(state, status);

    return {
      state: terminalState,
      events: [
        turnEvent(state.run.turn, "terminal_state", {
          status,
          reason: "player descended from the final floor",
        }),
      ],
    };
  }

  if (action.kind === "wait") {
    return {
      state,
      events: [],
    };
  }

