import { chebyshevDistance } from "@engine/map";
import type { RunAction } from "@engine/run";
import type { EntityInstance, GameState } from "@engine/state";
import { checkActionLegality, type PlayerAction } from "@engine/turn";

import {
  resolveKeyBinding,
  type KeyBindingContext,
  type KeyIntent,
} from "./keys";
import { autoTravelStopFor } from "./travel";
import type {
  InputFeedbackActionKind,
  PendingConfirm,
  UiSlice,
} from "@/store/game-store";

export type GameKeyPress = {
  readonly key: string;
  readonly repeat?: boolean;
};

export type InputDispatchResult =
  | {
      readonly status: "ignored";
      readonly reason: string;
      readonly preventDefault: false;
    }
  | {
      readonly status: "handled";
      readonly intent: KeyIntent["kind"];
      readonly preventDefault: true;
    }
  | {
      readonly status: "action_dispatched";
      readonly action: RunAction;
      readonly preventDefault: true;
    }
  | {
      readonly status: "confirm_required";
      readonly confirm: PendingConfirm;
      readonly preventDefault: true;
    }
  | {
      readonly status: "travel_stopped";
      readonly reason: string;
      readonly preventDefault: true;
    }
  | {
      readonly status: "input_locked";
      readonly preventDefault: true;
    };

export type InputDispatchSnapshot = {
  readonly gameState: GameState | null;
  readonly ui: UiSlice;
};

export type InputDispatchDeps = {
  readonly dispatchAction: (action: RunAction) => void;
  readonly patchUi: (patch: Partial<UiSlice>) => void;
  readonly appendInputFeedback: (
    actionKind: InputFeedbackActionKind,
    reason: string,
  ) => void;
  readonly lockInput: () => void;
};

export const dispatchGameKey = (
  snapshot: InputDispatchSnapshot,
  deps: InputDispatchDeps,
  keyPress: GameKeyPress,
): InputDispatchResult => {
  const context = inputFocusContext(snapshot.ui);
  const binding = resolveKeyBinding(keyPress.key, context);

  if (binding === null) {
    return {
      status: "ignored",
      reason: `unbound key in ${context}`,
      preventDefault: false,
    };
  }

  const intent = binding.intent;

  if (
    snapshot.ui.inputLocked &&
    intent.kind === "run_action"
  ) {
    return { status: "input_locked", preventDefault: true };
  }

  switch (intent.kind) {
    case "run_action":
      return dispatchRunAction(snapshot, deps, intent.action, keyPress);
    case "set_context_mode":
      deps.patchUi({
        contextPanelMode:
          snapshot.ui.contextPanelMode === intent.mode ? "inspect" : intent.mode,
      });
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "toggle_diary":
      deps.patchUi({
        diaryOpen: !snapshot.ui.diaryOpen,
        artifactOpen: false,
      });
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "open_keymap":
      deps.patchUi({ keymapOpen: true });
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "close_keymap":
      deps.patchUi({ keymapOpen: false });
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "close_top":
      closeTop(snapshot, deps);
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "request_abort":
      return requestAbortConfirm(snapshot, deps);
    case "confirm_yes":
      return confirmPending(snapshot, deps);
    case "confirm_no":
      cancelPendingConfirm(snapshot, deps);
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
  }
};

export const inputFocusContext = (ui: UiSlice): KeyBindingContext => {
  if (ui.keymapOpen) {
    return "overlay";
  }

  if (ui.diaryOpen || ui.artifactOpen) {
    return "paused-layer";
  }

  if (ui.pendingConfirm !== null) {
    return "confirm";
  }

  return "play";
};

export const dangerousConfirmForAction = (
  state: GameState,
  action: RunAction,
): PendingConfirm | null => {
  if (action.kind !== "descend" || !isPlayerAction(action)) {
    return null;
  }

  const legality = checkActionLegality(state, action);
  if (legality.status === "illegal") {
    return null;
  }

  const adjacentEnemy = adjacentEnemies(state)[0];
  if (adjacentEnemy === undefined) {
    return null;
  }

  return {
    action,
    prompt: `Enemy ${adjacentEnemy.id} is adjacent. Descend anyway? y/n`,
  };
};

const dispatchRunAction = (
  snapshot: InputDispatchSnapshot,
  deps: InputDispatchDeps,
  action: RunAction,
  keyPress: GameKeyPress,
): InputDispatchResult => {
  if (snapshot.gameState === null) {
    return {
      status: "ignored",
      reason: "game state not ready",
      preventDefault: false,
    };
  }

  if (keyPress.repeat === true && action.kind !== "move") {
    return {
      status: "ignored",
      reason: "non-move key repeat ignored",
      preventDefault: false,
    };
  }

  if (keyPress.repeat === true && action.kind === "move") {
    const stop = autoTravelStopFor(snapshot.gameState);
    if (stop !== null) {
      deps.appendInputFeedback("move", stop.message);
      return {
        status: "travel_stopped",
        reason: stop.reason,
        preventDefault: true,
      };
    }
  }

  const confirm = dangerousConfirmForAction(snapshot.gameState, action);
  if (confirm !== null) {
    deps.patchUi({ pendingConfirm: confirm });
    return {
      status: "confirm_required",
      confirm,
      preventDefault: true,
    };
  }

  deps.dispatchAction(action);
  deps.lockInput();

  return {
    status: "action_dispatched",
    action,
    preventDefault: true,
  };
};

const confirmPending = (
  snapshot: InputDispatchSnapshot,
  deps: InputDispatchDeps,
): InputDispatchResult => {
  const pending = snapshot.ui.pendingConfirm;
  if (pending === null) {
    return {
      status: "ignored",
      reason: "no pending confirm",
      preventDefault: false,
    };
  }

  deps.patchUi({ pendingConfirm: null });
  deps.dispatchAction(pending.action);
  deps.lockInput();

  return {
    status: "action_dispatched",
    action: pending.action,
    preventDefault: true,
  };
};

const requestAbortConfirm = (
  snapshot: InputDispatchSnapshot,
  deps: InputDispatchDeps,
): InputDispatchResult => {
  if (snapshot.ui.contextPanelMode !== "inspect") {
    deps.patchUi({ contextPanelMode: "inspect" });
    return {
      status: "handled",
      intent: "request_abort",
      preventDefault: true,
    };

  if (enemy?.kind !== "enemy" || grid === null) {
    return null;
  }

  const playerPosition = state.player.position;
  const candidates = MOVE_DIRECTIONS.map((entry) =>
    destinationForMove(playerPosition, entry.direction),
  ).filter((position) =>
    inBounds(grid, position) &&
    isWalkableTile(getTile(grid, position)) &&
    !isClosedDoor(getTile(grid, position)) &&
    !occupiedPredicate(state, enemyId)(position),
  );

  if (candidates.length === 0) {
    return null;
  }

  let best: Position | null = null;
  let bestDistance = Number.POSITIVE_INFINITY;

  for (const candidate of candidates) {
    const route = path(grid, enemy.position, candidate, {
      isOccupied: occupiedPredicate(state, enemyId),
    });

    if (route === null) {
      continue;
    }

    const distance = route.length;

    if (distance < bestDistance) {
      bestDistance = distance;
      best = candidate;
      continue;
    }

    if (
      distance === bestDistance &&
      best !== null &&
      comparePositions(candidate, best) < 0
    ) {
      best = candidate;
    }
  }

  return best;
};

const stepToward = (
  state: GameState,
  enemyId: EntityId,
  goal: Position,
  constraints: StepConstraints,
): BehaviorAction => {
  const enemy = state.entities[enemyId];
  const grid = gridFromState(state);

  if (enemy?.kind !== "enemy" || grid === null) {
    return { kind: "wait" };
  }

  if (isAdjacent(enemy.position, state.player.position)) {
    return { kind: "attack", targetId: "player" };
  }

  const route = path(grid, enemy.position, goal, {
    isOccupied: occupiedPredicate(state, enemyId),
  });

  if (route === null || route.length < 2) {
    return { kind: "wait" };
  }

  const next = route[1];

  if (next === undefined) {
    return { kind: "wait" };
  }

  if (!moveAllowed(state, enemyId, enemy.position, next, constraints)) {
    return { kind: "wait" };
  }

  const direction = directionBetween(enemy.position, next);

  return direction === null ? { kind: "wait" } : { kind: "move", direction };
};

const stepAwayFromPlayer = (
  state: GameState,
  enemyId: EntityId,
  constraints: StepConstraints,
): BehaviorAction => {
  const enemy = state.entities[enemyId];
  const grid = gridFromState(state);

  if (enemy?.kind !== "enemy" || grid === null) {
    return { kind: "wait" };
  }

  const playerPosition = state.player.position;
  const candidates = MOVE_DIRECTIONS.map((entry) => ({
    direction: entry.direction,
    position: destinationForMove(enemy.position, entry.direction),
  })).filter((candidate) =>
    moveAllowed(state, enemyId, enemy.position, candidate.position, constraints),
  );

  if (candidates.length === 0) {
    return { kind: "wait" };
  }

  const currentDistance = chebyshevDistance(enemy.position, playerPosition);
  let bestDistance = currentDistance;
  let bestCandidates = candidates;

  for (const candidate of candidates) {
    const nextDistance = chebyshevDistance(candidate.position, playerPosition);

    if (nextDistance > bestDistance) {
      bestDistance = nextDistance;
      bestCandidates = [candidate];
      continue;
    }

    if (nextDistance === bestDistance) {
      bestCandidates.push(candidate);
    }
  }

  if (bestDistance <= currentDistance && !constraints.maximizeDistance) {
    return { kind: "wait" };
  }

  const sorted = [...bestCandidates].sort((left, right) =>
    left.direction.localeCompare(right.direction),
  );
  const index =
    constraints.rng === undefined
      ? 0
      : rollInt(constraints.rng, 0, sorted.length - 1);
  const chosen = sorted[index];

  if (chosen === undefined) {
    return { kind: "wait" };
  }

  return { kind: "move", direction: chosen.direction };
};

const moveAllowed = (
  state: GameState,
  enemyId: EntityId,
  from: Position,
  to: Position,
  constraints: StepConstraints,
): boolean => {
  const grid = gridFromState(state);

  if (grid === null || !inBounds(grid, to)) {
    return false;
  }

  const tile = getTile(grid, to);

  if (!isWalkableTile(tile) || isClosedDoor(tile)) {
    return false;
  }

  if (occupiedPredicate(state, enemyId)(to)) {
    return false;
  }

  if (constraints.post !== undefined && constraints.tetherRadius !== undefined) {
    const fromDistance = chebyshevDistance(from, constraints.post);
    const toDistance = chebyshevDistance(to, constraints.post);

    if (
      fromDistance <= constraints.tetherRadius &&
      toDistance > constraints.tetherRadius
    ) {
      return false;
    }
  }

  return true;
};

const resolveEnemyMove = (
  state: GameState,
  enemyId: EntityId,
  direction: MoveDirection,
): TurnHookResult => {
  const enemy = state.entities[enemyId];
  const grid = gridFromState(state);

  if (enemy?.kind !== "enemy" || grid === null) {
    return { state, events: [] };
  }

  const from = enemy.position;
  const to = destinationForMove(from, direction);

  if (!inBounds(grid, to)) {
    return executeBehaviorAction(state, enemyId, { kind: "wait" });
  }

  const tile = getTile(grid, to);

  if (!isWalkableTile(tile) || isClosedDoor(tile)) {
    return executeBehaviorAction(state, enemyId, { kind: "wait" });
  }

  if (samePosition(to, state.player.position)) {
    const attackResult = resolveAttack(state, enemyId, "player");

    if ("illegal" in attackResult) {
      return executeBehaviorAction(state, enemyId, { kind: "wait" });
    }

    return attackResult;
  }

  if (occupiedPredicate(state, enemyId)(to)) {
    return executeBehaviorAction(state, enemyId, { kind: "wait" });
  }

  let nextState = withEnemyPosition(state, enemyId, to);
  nextState = advancePatrolRuntime(nextState, enemyId, from, to);

  if (playerVisible(nextState, enemyId)) {
    nextState = withEnemyBehaviorRuntime(nextState, enemyId, {
      patrolEngaged: true,
    });
  }

  return {
    state: nextState,
    events: [
      enemyEvent(state, "enemy_moved", {
        actorId: enemyId,
        from,
        to,
        direction,
      }),
    ],
  };
};

const advancePatrolRuntime = (
  state: GameState,
  enemyId: EntityId,
  from: Position,
  to: Position,
): GameState => {
  const enemy = state.entities[enemyId];

  if (enemy?.kind !== "enemy" || isPatrolEngaged(enemy)) {
    return state;
  }

  const waypoints = readWaypointList(enemy);

  if (waypoints.length === 0) {
    return state;
  }

  const index = patrolIndexFor(enemy) % waypoints.length;
  const waypoint = waypoints[index];

  if (waypoint === undefined || !samePosition(to, waypoint)) {
    return state;
  }

  return withEnemyBehaviorRuntime(state, enemyId, {
    patrolIndex: (index + 1) % waypoints.length,
  });
};

const occupiedPredicate =
  (state: GameState, selfId: EntityId) =>
  (position: Position): boolean => {
    if (samePosition(position, state.player.position)) {
      return true;
    }

    return Object.values(state.entities).some(
      (entity) =>
        (entity.kind === "enemy" || entity.kind === "npc") &&
        entity.id !== selfId &&
        samePosition(entity.position, position),
    );
  };

const withEnemyPosition = (
  state: GameState,
  enemyId: EntityId,
  position: Position,
): GameState => {
  const enemy = state.entities[enemyId];

  if (enemy?.kind !== "enemy") {
    return state;
  }

  return {
    ...state,
    entities: {
      ...state.entities,
      [enemyId]: {
        ...enemy,
        position,
      },
    },
  };
};

const withEnemyBehaviorRuntime = (
  state: GameState,
  enemyId: EntityId,
  patch: SerializableRecord,
): GameState => {
  const enemy = state.entities[enemyId];

  if (enemy?.kind !== "enemy") {
    return state;
  }

  return {
    ...state,
    entities: {
      ...state.entities,
      [enemyId]: {
        ...enemy,
        behaviorRuntime: {
          ...enemy.behaviorRuntime,
          ...patch,
        },
      },
    },
  };
};

const aiRngContextFor = (state: GameState): MutableRngContext => {
  const previousDraws = state.rng.streams[AI_RNG_STREAM_ID]?.draws ?? 0;
  const base = createRng(state.rng.rootSeed).fork(AI_RNG_STREAM_ID);

  for (let index = 0; index < previousDraws; index += 1) {
    base.nextUint32();
  }

  const context: MutableRngContext = {
    base,
    rng: base,
    initialDraws: previousDraws,
    drawsUsed: 0,
  };
  context.rng = trackingRng(context);

  return context;
};

const trackingRng = (context: MutableRngContext): Rng => ({
  nextUint32: () => drawUint32(context),
  fork: (label: string) => {
    const forkedBase = context.base.fork(label);
    const forkedContext: MutableRngContext = {
      base: forkedBase,
      rng: forkedBase,
      initialDraws: 0,
      drawsUsed: 0,
    };
    forkedContext.rng = trackingRng(forkedContext);

    return forkedContext.rng;
  },
  int: (min: number, max: number) => rollInt(context, min, max),
  pick: <T>(items: readonly T[]): T => {
    if (items.length === 0) {
      throw new RangeError("items must not be empty");
    }

    return items[rollInt(context, 0, items.length - 1)] as T;
  },
  weightedPick: <T>(items: readonly T[], weights: readonly number[]): T => {
    let total = 0;

    for (const weight of weights) {
      total += weight;
    }

    const roll = rollInt(context, 1, total);
    let runningTotal = 0;

    for (let index = 0; index < weights.length; index += 1) {
      runningTotal += weights[index] ?? 0;

      if (roll <= runningTotal) {
        return items[index] as T;
      }
    }

    return items[items.length - 1] as T;
  },
  shuffle: <T>(items: readonly T[]): T[] => {
    const shuffled = [...items];

    for (let index = shuffled.length - 1; index > 0; index -= 1) {
      const swapIndex = rollInt(context, 0, index);
      const value = shuffled[index];
      shuffled[index] = shuffled[swapIndex] as T;
      shuffled[swapIndex] = value as T;
    }

    return shuffled;
  },
  percent: (p: number) => rollInt(context, 1, 100) <= p,
});

